sql:
SELECT activity_id, user_id, activity_name
FROM activities
WHERE activity_name = 'Running' AND activity_date > CURRENT_DATE;

SELECT COUNT(DISTINCT goals.user_id) 
FROM goals
WHERE goals.goal_type = 'diet';

SELECT friendship_status, COUNT(*) as user_count
FROM friendships
GROUP BY friendship_status;

SELECT goal_id, AVG(progress) AS average_progress
FROM activity_goals
GROUP BY goal_id;

